-- [[ N0XY MASTER ENGINE V7 — RADIO UPDATE ]] --
local R=loadstring(game:HttpGet('https://raw.githubusercontent.com/SiriusSoftwareLtd/Rayfield/main/source.lua'))() local W=R:CreateWindow({Name="N0XY MASTER ENGINE 💀 (v7)",LoadingTitle="Загрузка N0XY CORE...",LoadingSubtitle="by N0XY",ConfigurationSaving={Enabled=false}}) local P=game:GetService("Players") local LP=P.LocalPlayer local RS=game:GetService("RunService") local L=game:GetService("Lighting") local flying,flySpeed,noclip,antiFling,wsVal,jpVal,targetName,loopFling,orbit,kAu,jrk,spin,szR=false,50,false,false,16,50,"",false,false,false,false,false,false _G.Aim,_G.AutoClick=false,false local ST={Space="rbxassetid://159454286",Fire="rbxassetid://1760874933",Night="rbxassetid://12128522303"} local musicId="" local function getT() for _,p in pairs(P:GetPlayers()) do if p.Name:lower():sub(1,#targetName)==targetName or p.DisplayName:lower():sub(1,#targetName)==targetName then return p end end return nil end local function setAnim(id) pcall(function() local c=LP.Character if c and c:FindFirstChild("Animate") then local s={walk="WalkAnim",run="RunAnim",jump="JumpAnim",idle="IdleAnim"} for k,v in pairs(s) do local a=c.Animate:FindFirstChild(v) if a and a:FindFirstChildOfClass("Animation") then a:FindFirstChildOfClass("Animation").AnimationId="rbxassetid://"..id end end local h=c:FindFirstChildOfClass("Humanoid") if h then h:ChangeState(Enum.HumanoidStateType.Inaction) end end end) end local T1=W:CreateTab("Главная & PvP ⚔️",0) local T2=W:CreateTab("Мир & Небо 🌌",0) local T3=W:CreateTab("Троллинг Цели 😈",0) local T4=W:CreateTab("Хаос Сервера 💥",0) local T5=W:CreateTab("Анимации 🎭",0) local T6=W:CreateTab("Радио 🎵",0) local FlyC T1:CreateToggle({Name="Fly (Полёт по камере)",CurrentValue=false,Flag="FlyFlag",Callback=function(v) flying=v if flying then local C=LP.Character or LP.CharacterAdded:Wait() local H=C:WaitForChild("HumanoidRootPart") local Hum=C:WaitForChild("Humanoid") local Cam=workspace.CurrentCamera Hum.PlatformStand=true FlyC=RS.Heartbeat:Connect(function(dt) if not flying or not C or not H.Parent then if FlyC then FlyC:Disconnect() end return end local md=Hum.MoveDirection if md.Magnitude>0 then local fd=(Cam.CFrame*CFrame.new(Vector3.new(md.X,0,md.Z))).LookVector H.CFrame=H.CFrame+(fd*(flySpeed*dt)) end H.Velocity=Vector3.new(0,0,0) end) else if FlyC then FlyC:Disconnect() end pcall(function() LP.Character.Humanoid.PlatformStand=false end) end end}) T1:CreateInput({Name="Скорость Полета",PlaceholderText="Стандарт: 50",Callback=function(t) local n=tonumber(t) if n then flySpeed=n end end}) T1:CreateSlider({Name="Скорость Бега (WalkSpeed)",Range={16,250},Increment=5,CurrentValue=16,Callback=function(v) wsVal=v end}) T1:CreateSlider({Name="Сила Прыжка (JumpPower)",Range={50,300},Increment=5,CurrentValue=50,Callback=function(v) jpVal=v end}) T1:CreateToggle({Name="Noclip (Сквозь стены)",CurrentValue=false,Flag="NoclipFlag",Callback=function(v) noclip=v end}) T1:CreateToggle({Name="Anti-Fling (Защита от толчков)",CurrentValue=false,Flag="AntiFlingFlag",Callback=function(v) antiFling=v end}) T1:CreateToggle({Name="Aim-Lock (Наводка)",CurrentValue=false,Callback=function(v) _G.Aim=v end}) T1:CreateToggle({Name="Auto-Clicker (Авто-удар)",CurrentValue=false,Callback=function(v) _G.AutoClick=v end}) T2:CreateDropdown({Name="Выбрать небо (Skybox)",Options={"Space","Fire","Night"},Callback=function(o) local s=L:FindFirstChildOfClass("Sky") or Instance.new("Sky",L) s.SkyboxBk=ST[o] s.SkyboxDn=ST[o] s.SkyboxFt=ST[o] s.SkyboxLf=ST[o] s.SkyboxRt=ST[o] s.SkyboxUp=ST[o] end}) T2:CreateButton({Name="Fog Disable (Убрать туман)",Callback=function() L.FogEnd=100000 end}) T2:CreateSlider({Name="Гравитация Мира 🌍",Range={0,400},Increment=10,CurrentValue=196,Callback=function(v) workspace.Gravity=v end}) T2:CreateButton({Name="Включить Вечную Ночь 🌙",Callback=function() L.TimeOfDay="00:00:00" end}) T2:CreateButton({Name="Включить Вечный День ☀️",Callback=function() L.TimeOfDay="12:00:00" end}) T3:CreateInput({Name="Ник жертвы",PlaceholderText="Можно первые буквы...",Callback=function(t) targetName=t:lower() end}) T3:CreateButton({Name="Посадить в РЕАЛЬНУЮ клетку! 🧱",Callback=function() local p=getT() if p and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then local tH=p.Character.HumanoidRootPart if workspace:FindFirstChild("RealCage_"..p.Name) then workspace["RealCage_"..p.Name]:Destroy() end local CM=Instance.new("Model",workspace) CM.Name="RealCage_"..p.Name local fl=Instance.new("Part",CM) fl.Size=Vector3.new(8,0.5,8) fl.CFrame=tH.CFrame*CFrame.new(0,-3.5,0) fl.Anchored=true fl.Material=Enum.Material.CorrodedMetal local rf=Instance.new("Part",CM) rf.Size=Vector3.new(8,0.5,8) rf.CFrame=tH.CFrame*CFrame.new(0,4.5,0) rf.Anchored=true rf.Material=Enum.Material.CorrodedMetal local function sb(o) local b=Instance.new("Part",CM) b.Size=Vector3.new(0.2,8,0.2) b.CFrame=tH.CFrame*o b.Anchored=true b.Material=Enum.Material.Iron b.Color=Color3.fromRGB(100,100,100) end for k=-3.5,3.5,1.2 do sb(CFrame.new(k,0.5,-3.5)) sb(CFrame.new(k,0.5,3.5)) sb(CFrame.new(-3.5,0.5,k)) sb(CFrame.new(3.5,0.5,k)) end R:Notify({Title="N0XY HUB",Content=p.Name.." за решёткой!",Duration=3}) end end}) T3:CreateButton({Name="Удалить все клетки ❌",Callback=function() for _,v in pairs(workspace:GetChildren()) do if v.Name:sub(1,9)=="RealCage_" then v:Destroy() end end end}) T3:CreateToggle({Name="Loop Fling (Кошмарить вечно)",CurrentValue=false,Callback=function(v) loopFling=v task.spawn(function() while loopFling do pcall(function() local p=getT() if p and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then local mH=LP.Character.HumanoidRootPart mH.CFrame=p.Character.HumanoidRootPart.CFrame*CFrame.new(math.random(-1,1),0,math.random(-1,1)) mH.Velocity=Vector3.new(7000,7000,7000) mH.RotVelocity=Vector3.new(7000,7000,7000) end end) task.wait(0.01) end end) end}) T3:CreateToggle({Name="Orbit (Летать вокруг кругами)",CurrentValue=false,Callback=function(v) orbit=v task.spawn(function() local a=0 while orbit do pcall(function() local p=getT() if p and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then a=a+0.1 LP.Character.HumanoidRootPart.CFrame=CFrame.new(p.Character.HumanoidRootPart.Position+Vector3.new(math.sin(a)*6,2,math.cos(a)*6),p.Character.HumanoidRootPart.Position) end end) task.wait(0.01) end end) end}) T3:CreateButton({Name="Void Fling (Скинуть под карту) 🕳️",Callback=function() local p=getT() if p and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then p.Character.HumanoidRootPart.CFrame=CFrame.new(0,-500,0) end end}) local fz=false T3:CreateToggle({Name="Freeze Target (Заморозить цель) ❄️",CurrentValue=false,Callback=function(v) fz=v task.spawn(function() while fz do local p=getT() if p and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then p.Character.HumanoidRootPart.Anchored=true end task.wait(0.1) end local p=getT() if p and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then p.Character.HumanoidRootPart.Anchored=false end end) end}) T4:CreateToggle({Name="Ломаная Анимация 💀",CurrentValue=false,Callback=function(v) jrk=v local c=LP.Character if not c then return end if jrk then local an=c:FindFirstChild("Animate") if an then an:Destroy() end local hu=c:FindFirstChildOfClass("Humanoid") if hu then for _,t in pairs(hu:GetPlayingAnimationTracks()) do t:Stop() end end task.spawn(function() while jrk and c and c.Parent do pcall(function() for _,j in pairs(c:GetDescendants()) do if j:IsA("Motor6D") then j.C0=j.C0*CFrame.Angles(math.rad(math.random(-20,20)),math.rad(math.random(-20,20)),math.rad(math.random(-20,20))) end end end) task.wait(0.01) end end) else R:Notify({Title="N0XY HUB",Content="Сделай Reset персонажа!",Duration=4}) end end}) T4:CreateButton({Name="Уничтожитель предметов 🗑️",Callback=function() for _,v in pairs(workspace:GetDescendants()) do if v:IsA("Part") and not v.Anchored and not v:IsDescendantOf(LP.Character) then v:Destroy() end end end}) T4:CreateToggle({Name="Kill Aura (Дамаг вокруг)",CurrentValue=false,Callback=function(v) kAu=v task.spawn(function() while kAu do pcall(function() local mH=LP.Character.HumanoidRootPart for _,p in pairs(P:GetPlayers()) do if p~=LP and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then if (mH.Position-p.Character.HumanoidRootPart.Position).Magnitude<15 then local tl=LP.Character:FindFirstChildOfClass("Tool") if tl then tl:Activate() end end end end end) task.wait(0.1) end end) end}) T4:CreateButton({Name="Стянуть все блоки к себе 🧲",Callback=function() local mH=LP.Character and LP.Character:FindFirstChild("HumanoidRootPart") if mH then for _,pt in pairs(workspace:GetDescendants()) do if pt:IsA("BasePart") and not pt.Anchored and not pt:IsDescendantOf(LP.Character) then pt.CFrame=mH.CFrame+Vector3.new(0,2,0) end end end end}) T5:CreateButton({Name="Mage Animation (Маг)",Callback=function() setAnim("707827244") end}) T5:CreateButton({Name="Ninja Animation (Ниндзя)",Callback=function() setAnim("616111377") end}) T5:CreateButton({Name="Zombie Animation (Зомби)",Callback=function() setAnim("616156730") end}) T5:CreateButton({Name="Werewolf Animation (Оборотень)",Callback=function() setAnim("1016149174") end}) T6:CreateInput({Name="ID Музыки",PlaceholderText="Введи ID звука...",Callback=function(t) musicId=t end}) T6:CreateButton({Name="Включить музыку 🔊",Callback=function() pcall(function() local s=workspace:FindFirstChild("N0XY_Radio") or Instance.new("Sound",workspace) s.Name="N0XY_Radio" s.SoundId="rbxassetid://"..musicId s.Volume=2 s.Looped=true s:Play() end) end}) T6:CreateButton({Name="Остановить 🔇",Callback=function() pcall(function() local s=workspace:FindFirstChild("N0XY_Radio") if s then s:Stop() s:Destroy() end end) end}) RS.RenderStepped:Connect(function() if _G.Aim then local nr=nil local di=math.huge for _,p in pairs(P:GetPlayers()) do if p~=LP and p.Character and p.Character:FindFirstChild("Head") then local d=(p.Character.Head.Position-LP.Character.Head.Position).Magnitude if d<di then nr=p.Character.Head di=d end end end if nr then workspace.CurrentCamera.CFrame=CFrame.new(workspace.CurrentCamera.CFrame.Position,nr.Position) end end if _G.AutoClick then local tl=LP.Character:FindFirstChildOfClass("Tool") if tl then tl:Activate() end end end) RS.Stepped:Connect(function() if noclip and LP.Character then for _,pt in pairs(LP.Character:GetDescendants()) do if pt:IsA("BasePart") then pt.CanCollide=false end end end if antiFling and LP.Character then pcall(function() for _,pt in pairs(LP.Character:GetDescendants()) do if pt:IsA("BasePart") then pt.Velocity=Vector3.new(0,0,0) pt.RotVelocity=Vector3.new(0,0,0) end end end) end end) task.spawn(function() while true do pcall(function() if LP.Character and LP.Character:FindFirstChild("Humanoid") then local hu=LP.Character.Humanoid if hu.WalkSpeed~=wsVal and not flying then hu.WalkSpeed=wsVal end if hu.JumpPower~=jpVal then hu.UseJumpPower=true hu.JumpPower=jpVal end end end) task.wait(0.1) end end)
          
